content.problemStatement:
What will be the output of the following C++ program?

```cpp
#include 
using namespace std;

class Employee {
public:
    string name;

    Employee() {
        name = "Unknown Employee";
    }

    void displayEmployeeInfo() {
        cout << "Employee Name: " << name << endl;
    }
};

class Manager : public Employee {
public:
    string department;

    Manager() {
        department = "HR";
    }

    void displayManagerInfo() {
        cout << "Department: " << department << endl;
    }
};

class Director : public Manager {
public:
    int teamSize;

    Director() {
        teamSize = 10;
    }

    void displayDirectorInfo() {
        cout << "Team Size: " << teamSize << endl;
    }
};

int main() {
    Director d;
    d.name = "John Smith";  // From Employee class
    d.department = "Finance"; // From Manager class
    d.teamSize = 20;         // From Director class

    d.displayEmployeeInfo(); // Employee class method
    d.displayManagerInfo();  // Manager class method
    d.displayDirectorInfo(); // Director class method

    return 0;
}
```

